const express = require('express');
const { MongoClient, ObjectId } = require('mongodb');

const app = express();
app.use(express.json());

const MONGO_URI = process.env.MONGO_URI || 'mongodb://localhost:27017';
const DB_NAME = process.env.DB_NAME || 'querydb';

let db;

MongoClient.connect(MONGO_URI, { useUnifiedTopology: true })
  .then(client => {
    db = client.db(DB_NAME);
    console.log('Connected to MongoDB');
  })
  .catch(err => {
    console.error('MongoDB connection error:', err);
    process.exit(1);
  });

app.post('/api/query/:collection', async (req, res) => {
  try {
    const { collection } = req.params;
    const { filter = {}, projection = {}, sort = {}, limit = 100, skip = 0 } = req.body;

    const processedFilter = processFilter(filter);

    const results = await db.collection(collection)
      .find(processedFilter)
      .project(projection)
      .sort(sort)
      .limit(limit)
      .skip(skip)
      .toArray();

    res.json({
      success: true,
      count: results.length,
      data: results
    });
  } catch (error) {
    res.status(500).json({
      success: false,
      error: error.message
    });
  }
});

